import {
  InverterSettingsDto,
  InverterStatus,
} from '../dto/inverter-settings.dto';
import { InverterModel } from '../../types';
import { localize } from '../../localize/localize';

/* Solaredge Status Codes
 * source https://knowledge-center.solaredge.com/sites/kc/files/sunspec-implementation-technical-note.pdf
 *
 * 1 = Off
 * 2 = Sleeping (auto-shutdown) – Night mode
 * 3 = Grid Monitoring/wake-up
 * 4 = Inverter is ON and producing power
 * 5 = Production (curtailed)
 * 6 = Shutting down
 * 7 = Fault
 * 8 = Maintenance/setup
 */

export class SolarEdge extends InverterSettingsDto {
  brand = InverterModel.SolarEdge;
  statusGroups: InverterStatus = {
    standby: {
      states: ['0', '1', '2', '3', '6', 'standby', 'stand-by'],
      color: 'blue',
      message: localize('common.standby'),
    },
    selftest: {
      states: ['8', 'selftest', 'self-checking'],
      color: 'yellow',
      message: localize('common.selftest'),
    },
    normal: {
      states: ['4', 'normal', 'ok'],
      color: 'green',
      message: localize('common.normal'),
    },
    alarm: {
      states: ['5', 'alarm'],
      color: 'orange',
      message: localize('common.alarm'),
    },
    fault: {
      states: ['7', 'fault'],
      color: 'red',
      message: localize('common.fault'),
    },
  };
  image =
    'data:image/png;base64,';
}
